#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline int max(int x,int y){return x>y?x:y;}
inline int min(int x,int y){return x<y?x:y;}
const int N=1e6+10,INF=0x3f3f3f3f,Mod=1e9+7;int pm[N>>2],cpt,ph[N];bool vs[N];
double inv[N];inline void Init()
{
	ph[1]=1;inv[1]=1;rep(2,1000000,i)
	{
		inv[i]=1./i+1e-12;if(!vs[i])ph[pm[++cpt]=i]=i-1;
		for(int j=1;j<=cpt&&pm[j]*i<=1000000;++j)
		{
			vs[pm[j]*i]=1;if(i%pm[j]==0){ph[pm[j]*i]=ph[i]*pm[j];break;}
			ph[pm[j]*i]=ph[i]*(pm[j]-1);
		}
	}
	rep(2,1000000,i)ph[i]+=ph[i-1],ph[i]>Mod?ph[i]-=Mod:0; 
}
//inline int nxt(int n,int x){return (n/x)?n/(n/x):INF;}
inline int nxt(int n,int x){ return int(n*inv[x])?int(n*inv[int(n*inv[x])]):INF;}
inline int dn(int x){return x>Mod?x-Mod:x;}inline int up(int x){return x<0?x+Mod:x;}
inline void Solve()
{
	int a1=read()-1,b1=read()-1,a2=read(),b2=read(),n=max(a2,b2),ans=0;
//	printf("n :: %d\n",n);
	for(int l=1,r=0;l<=n;l=r+1)
	{
		r=min(min(min(nxt(a1,l),nxt(b1,l)),nxt(a2,l)),nxt(b2,l));
		ans=dn(ans+1ll*up(ph[r]-ph[l-1])*up(int(a2*inv[l])-int(a1*inv[l]))%Mod*up(int(b2*inv[l])-int(b1*inv[l]))%Mod);
//		printf("debug :: %d %d %d %d\n",up(ph[r]-ph[l-1]),up(int(a2*inv[l])-int(a1*inv[l])),up(int(b2*inv[l])-int(b1*inv[l])));
	}
	printf("%d\n",ans);return;
}
int main(){Init();int T=read();read();read();while(T--)Solve();return 0;}
